#include <bits/stdc++.h>
using namespace std;
string s;
int nxt[20004];
string dfs(int x,int y){
	string sum="";
	int d=0;
	for(int i=x;i<=y;i++){
		if(s[i]=='[')
			sum+=dfs(i+1,nxt[i]-1),i=nxt[i];
		else if(s[i]>='0' && s[i]<='9')
			d=d*10+s[i]-'0';
		else if(s[i]>='A' && s[i]<='Z')
			sum+=s[i];
	}
	if(!d)
		d=1;
	string tmp="";
	for(int i=0;i<d;i++)
		tmp+=sum;
	return tmp;
}
int main(){
	stack<int> st;
	cin>>s;
	for(int i=0;i<s.size();i++){
		if(s[i]=='[')
			st.push(i);
		else if(s[i]==']')
			nxt[st.top()]=i,st.pop();
	}
	cout<<dfs(0,s.size()-1);
	return 0;
}
